Here is a simple JSON schema for a customer profile:

```json
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Customer Profile",
  "type": "object",
  "properties": {
    "firstName": {
      "type": "string",
      "description": "The first name of the customer"
    },
    "lastName": {
      "type": "string",
      "description": "The last name of the customer"
    },
    "email": {
      "type": "string",
      "format": "email",
      "description": "The email address of the customer"
    },
    "phone": {
      "type": "string",
      "pattern": "^\\+?[0-9]{1,4}?[-. ]?[0-9]{2,4}?[-. ]?[0-9]{2,4}?[-. ]?[0-9]{2,4}$",
      "description": "The phone number of the customer"
    },
    "address": {
      "type": "object",
      "properties": {
        "street": {
          "type": "string",
          "description": "The street address of the customer"
        },
        "city": {
          "type": "string",
          "description": "The city of the customer"
        },
        "state": {
          "type": "string",
          "description": "The state of the customer"
        },
        "postalCode": {
          "type": "string",
          "description": "The postal code of the customer"
        },
        "country": {
          "type": "string",
          "description": "The country of the customer"
        }
      },
      "required": ["street", "city", "state", "postalCode", "country"]
    },
    "dateOfBirth": {
      "type": "string",
      "format": "date",
      "description": "The date of birth of the customer"
    },
    "gender": {
      "type": "string",
      "enum": ["Male", "Female", "Other"],
      "description": "The gender of the customer"
    },
    "loyaltyProgramMember": {
      "type": "boolean",
      "description": "Indicates if the customer is a member of the loyalty program"
    }
  },
  "required": ["firstName", "lastName", "email", "address"]
